mapper.sql:
select ti.thumb_url, ti.image_name fileName, ti.image_path, ti.format, ti.width, ti.height, ti.resolution_x, ti.resolution_y, ti.source_lens, ti.image_id, ti.image_name, ti.group_code, ti.wax_code, ti.animal_code, ti.sex_flag, ti.topic_name, su.nick_name as user_name, fs.create_time, fs.description, fs.slide_id, ${params.currentUserId} as is_view, fs.viewers from fr_slide fs left join tb_image ti on fs.image_id = ti.image_id left join sys_user su on fs.create_by = su.user_id
fs.special_id = #{params.projectId} and fs.del_flag='0'
and ti.image_name like concat('%',#{params.fileName},'%')
and ti.animal_code like concat('%',#{params.animalCode},'%')
and fs.description like concat('%',#{params.description},'%')
and ti.sex_flag = #{params.genderFlag}
and ${params.currentUserId}
and not ${params.currentUserId}
and ti.group_code = #{params.groupCode}
and ti.wax_code = #{params.waxCode}
and su.nick_name like concat('%',#{params.createBy},'%')
AND date_format(fs.create_time,'%Y%m%d') >= date_format(#{params.createTimeParams.beginTime},'%Y%m%d')
AND date_format(fs.create_time,'%Y%m%d') <= date_format(#{params.createTimeParams.endTime},'%Y%m%d')
order by ${params.sortField} ${params.sortType}
order by ti.animal_code asc,ti.wax_code_order asc,ti.group_code asc,ti.sex_flag asc

mapper.select:
select frs.topic_name,frs.special_name,ti.image_name,tg.organ_name,af.quantitative_indicators,af.unit,af.results,af.forecast_range from fr_slide fs left join tb_image ti on fs.image_id = ti.image_id left join fr_special frs on fs.special_id=frs.special_id left join fr_single_slide fss on fs.slide_id=fss.slide_id left join tb_organ_tag tg on fss.category_id=tg.organ_tag_id left join fr_ai_forecast af on af.single_slide_id=fss.single_id where fs.special_id=#{projectId}
and fss.single_id=#{singleId}
and fss.category_id=#{categoryId}

select af.structure_ids,fss.category_id,tg.organ_name,af.quantitative_indicators,af.unit,af.results,af.forecast_range from fr_single_slide fss left join fr_ai_forecast af on af.single_slide_id=fss.single_id left join fr_slide fs on fs.slide_id=fss.slide_id left join tb_image ti on fs.image_id = ti.image_id left join fr_special frs on fs.special_id=frs.special_id left join tb_organ_tag tg on fss.category_id=tg.organ_tag_id where fs.del_flag='0'
and fs.special_id=#{projectId}
and fs.slide_id=#{slideId}
and af.single_slide_id=#{singleSlideId}

SELECT b.slide_id AS slideId, c.thumb_url AS thumbUrl, c.image_name AS fileName, c.image_name AS imageName, c.animal_code AS animalCode, c.wax_code AS waxCode, c.group_code AS groupCode, c.sex_flag AS genderFlag, a.viewStatus AS viewStatus, b.ai_status AS aiStatus, b.description AS description, b.create_time AS createTime FROM (SELECT a.slide_id, ${params.currentUserId} AS viewStatus FROM fr_slide a LEFT JOIN tb_image b ON a.image_id = b.image_id LEFT JOIN fr_single_slide c ON a.slide_id = c.slide_id WHERE a.del_flag = '0' AND a.special_id = #{params.projectId}
and b.image_name like concat('%',#{params.fileName},'%')
AND b.animal_code IN
#{item}
AND b.wax_code IN
#{item}
AND b.group_code IN
#{item}
AND b.sex_flag = #{params.genderFlag}
AND c.category_id IN
#{item}
AND ${params.currentUserId} = #{params.viewStatus}
AND (a.ai_status IN
#{item}
OR CASE WHEN c.forecast_status = '3' OR c.ai_status_fine = 3 THEN 5 WHEN c.forecast_status = '1' OR c.ai_status_fine = 1 THEN 6 WHEN c.forecast_status = '2' OR c.ai_status_fine = 2 THEN 7 WHEN c.single_id IS NOT NULL THEN 4 ELSE NULL END IN
#{item}
)
and a.description like concat('%',#{params.description},'%')
AND date_format(a.create_time,'%Y%m%d') >= date_format(#{params.createTimeParams.beginTime},'%Y%m%d')
AND date_format(a.create_time,'%Y%m%d') <= date_format(#{params.createTimeParams.endTime},'%Y%m%d')
GROUP BY a.slide_id) a JOIN fr_slide b ON a.slide_id = b.slide_id LEFT JOIN tb_image c ON b.image_id = c.image_id ORDER BY c.animal_code ASC, c.wax_code_order ASC, c.group_code ASC, c.sex_flag ASC

SELECT b.slide_id AS slideId, c.thumb_url AS thumbUrl, c.image_name AS fileName, c.image_name AS imageName, c.animal_code AS animalCode, c.wax_code AS waxCode, c.group_code AS groupCode, c.sex_flag AS genderFlag, a.viewStatus AS viewStatus, b.ai_status AS aiStatus, b.description AS description, b.create_time AS createTime FROM (SELECT a.slide_id, ${params.currentUserId} AS viewStatus FROM fr_slide a LEFT JOIN tb_image b ON a.image_id = b.image_id LEFT JOIN fr_single_slide c ON a.slide_id = c.slide_id WHERE a.del_flag = '0' AND a.special_id = #{params.projectId}
and b.image_name like concat('%',#{params.fileName},'%')
AND b.animal_code IN
#{item}
AND b.wax_code IN
#{item}
AND b.group_code IN
#{item}
AND b.sex_flag = #{params.genderFlag}
AND c.category_id IN
#{item}
AND ${params.currentUserId} = #{params.viewStatus}
AND (a.ai_status IN
#{item}
OR CASE WHEN c.forecast_status = '3' OR c.ai_status_fine = 3 THEN 5 WHEN c.forecast_status = '1' OR c.ai_status_fine = 1 THEN 6 WHEN c.forecast_status = '2' OR c.ai_status_fine = 2 THEN 7 WHEN c.single_id IS NOT NULL THEN 4 ELSE NULL END IN
#{item}
)
and a.description like concat('%',#{params.description},'%')
AND date_format(a.create_time,'%Y%m%d') >= date_format(#{params.createTimeParams.beginTime},'%Y%m%d')
AND date_format(a.create_time,'%Y%m%d') <= date_format(#{params.createTimeParams.endTime},'%Y%m%d')
GROUP BY a.slide_id) a JOIN fr_slide b ON a.slide_id = b.slide_id LEFT JOIN tb_image c ON b.image_id = c.image_id ORDER BY c.animal_code ASC, c.wax_code_order ASC, c.group_code ASC, c.sex_flag ASC
